import React, { useState, useEffect } from "react";

const DesignerForm = ({ onSubmit, initialData }) => {
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    type: "",
    previousDesigns: ""
  });

  // When editing, load existing data
  useEffect(() => {
    if (initialData) {
      setFormData({
        ...initialData,
        // Convert array from DB into comma-separated string for input
        previousDesigns: Array.isArray(initialData.previousDesigns)
          ? initialData.previousDesigns.join(", ")
          : initialData.previousDesigns || ""
      });
    }
  }, [initialData]);

  // Handle form field changes
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  // Handle submit
  const handleSubmit = (e) => {
    e.preventDefault();

    // Normalize previousDesigns into array
    let previousDesigns = formData.previousDesigns;
    if (typeof previousDesigns === "string") {
      previousDesigns = previousDesigns
        .split(",")
        .map((d) => d.trim())
        .filter((d) => d.length > 0);
    }

    const designerData = {
      ...formData,
      previousDesigns
    };

    onSubmit(designerData);
  };

  return (
    <form onSubmit={handleSubmit} style={{ maxWidth: "400px", margin: "auto" }}>
      <div>
        <label>Name:</label>
        <input
          type="text"
          name="name"
          value={formData.name || ""}
          onChange={handleChange}
          required
        />
      </div>

      <div>
        <label>Email:</label>
        <input
          type="email"
          name="email"
          value={formData.email || ""}
          onChange={handleChange}
          required
        />
      </div>

      <div>
        <label>Type:</label>
        <select
          name="type"
          value={formData.type || ""}
          onChange={handleChange}
          required
        >
          <option value="">-- Select Type --</option>
          <option value="fashion">Fashion</option>
          <option value="graphic">Graphic</option>
          <option value="interior">Interior</option>
        </select>
      </div>

      <div>
        <label>Previous Designs (comma separated):</label>
        <input
          type="text"
          name="previousDesigns"
          value={formData.previousDesigns || ""}
          onChange={handleChange}
        />
      </div>

      <button type="submit">
        {initialData ? "Update Designer" : "Add Designer"}
      </button>
    </form>
  );
};

export default DesignerForm;
